head.script:
scwin.initData = {
	"chart" : {
		"prdctnChartUnit" : 10,
		"prdctnChartIntervalCount" : 5,
		"cnstnChartUnit" : 10,
		"cnstnChartIntervalCount" : 3
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	grdPrdctnSttusDeptByList.setHeaderClass("hMlyEpwrDelngQy", "border-right");
	grdPrdctnSttusSetcscList.setHeaderClass("hMlyEpwrDelngQy", "border-right");
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSPN2000000", {"initScreenCallback" : scwin.searchDatas});
	//ecsLib.setChartResizeObserver(this);
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	var strtDt = utilLib.getCurrentDate("yyyyMM");
	var basinCd = "ALL";
	var setcscDivCd = "ALL";

	// var today = utilLib.getCurrentDate();
	var params = $p.getParameter("param");
	if (params) {
		if (params.year) {
			if (params.month) {
				strtDt = String(params.year) + String(params.month);
			} else {
				if (strtDt.substr(0, 4) == params.year) {
					strtDt = String(params.year) + strtDt.substr(4, 2);
				} else {
					strtDt = String(params.year) + "12";
				}
				// today = String(params.year) + "1231";
			}
		}
		if (params.basinCd) {
			basinCd = params.basinCd;
			acbBasin.setValue(basinCd);
		}
		if (params.setcscDivCd) {
			setcscDivCd = params.setcscDivCd;
			acbSetcsc.setValue(setcscDivCd);
		}
	}

	dmaSearchParam.set("strtDt", strtDt);
	dmaSearchParam.set("basinCd", basinCd);
	dmaSearchParam.set("setcscCd", setcscDivCd);
	dmaSearchParam.set("deptCd", "ALL");
	dmaSearchParam.set("cnd", radSeletChart.getValue());
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");

	if (String(strtDate).length != 6) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

	var action = "";
	var resData = "";
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		action = "pn/prdctnsttus/retrieve-prdctn-sttus-setcsc.do";
		resData = dltPrdctnSttusSetcscByList;
	} else if (tabIdx == 1) {
		action = "pn/prdctnsttus/retrieve-prdctn-sttus-dept.do";
		resData = dltPrdctnSttusDeptByList;
	}

	var option = {
		action : action
			+ queryString,
		method : "get",
		resData : resData,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 그리드 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		if (dltPrdctnSttusSetcscByList.getAllJSON().length > 0) {
			grdPrdctnSttusSetcscList.setFocusedCell(0, 0);
		}
	} else if (tabIdx == 1) {
		if (dltPrdctnSttusDeptByList.getAllJSON().length > 0) {
			grdPrdctnSttusDeptByList.setFocusedCell(0, 0);
		}
	}

	scwin.grdPrdctnSttusList_oncellclick(0, 0);
}

/**
 * 특정 셀을 선택시 해당 데이터를 차트로 표출한다.
 * @param <Int> row
 * @param <Int> col
 * @return
 */
scwin.grdPrdctnSttusList_oncellclick = function(row, col) {
	var rowData = "";
	var cellData = "";
	var action = "";
	var resData = "";

	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var cnd = dmaSearchParam.get("cnd");
	var tabIdx = tabControl.getSelectedTabIndex();

	if (tabIdx == 0) {
		rowData = grdPrdctnSttusSetcscList.getRowJSON(row);
		cellData = grdPrdctnSttusSetcscList.getCellData(row, "cmmnCd");
		action = "pn/prdctnsttus/retrieve-prdctn-sttus-setcsc-chart.do";
		resData = dltPrdctnSttusSetcscByChartList;
		ecsSetcscDivCd = cellData;
	} else if (tabIdx == 1) {
		rowData = grdPrdctnSttusDeptByList.getRowJSON(row);
		cellData = grdPrdctnSttusDeptByList.getCellData(row, "deptCd");
		action = "pn/prdctnsttus/retrieve-prdctn-sttus-dept-chart.do";
		resData = dltPrdctnSttusDeptByChartList;
		ecsChrgDeptId = cellData;
	}

	// 차트 데이터 조회
	var strtDate = dmaSearchParam.get("strtDt");

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
	queryString += `&cnd=${cnd}`;

	var option = {
		action : action
			+ queryString,
		method : "get",
		resData : resData,
		success : "scwin.inqireChartCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
}

/**
 * 차트 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireChartCallback = function() {
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		// 발전원별 차트 생성
		scwin.searchChartSetcsc();
	} else if (tabIdx == 1) {
		// 부서별 차트 생성
		scwin.searchChartDept();
	}
}

/**
 * 탭 변경에 따라 조회
 * @param
 * @return
 */
scwin.tabControl_ontabclick = function(tabID, idx) {
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("setcscCd", "ALL");
	dmaSearchParam.set("deptCd", "ALL");
	acbBasin.setSelectedIndex(0);
	acbSetcsc.setSelectedIndex(0);
	acbDept.setSelectedIndex(0);

	if (idx == 0) {
		grdPrdctnSttusSetcscList.setHeaderClass("hMlyEpwrDelngQy", "border-right");
	} else if (idx == 1) {
		grdPrdctnSttusDeptByList.setHeaderClass("hMlyEpwrDelngQy", "border-right");
		if (dltPrdctnSttusDeptByList.getAllJSON().length < 1) {
			scwin.btnInqire_onclick();
		}
	}
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=dept"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbSetcsc_onviewchange = function(info) {
	var ecsSetcscDivCd = info.newValue;
	dmaSearchParam.set("setcscCd", ecsSetcscDivCd);
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;

	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=dept"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbMngDept_onviewchange = function(info) {
	dmaSearchParam.set("deptCd", info.newValue);
};

scwin.radSeletChart_onviewchange = function(info) {
	var row = 0;
	dmaSearchParam.set("cnd", info.value);

	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		row = grdPrdctnSttusSetcscList.getFocusedRowIndex();
	} else if (tabIdx == 1) {
		row = grdPrdctnSttusDeptByList.getFocusedRowIndex();
	}
	scwin.grdPrdctnSttusList_oncellclick(row);
};

/**
 * 그리드 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplZeroFrmt = function(value) {
	return ecsLib.dsplZeroFrmt(value, 1);
};

/**
 * 그리드 합계 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplFrmt = function(value) {
	return ecsLib.dsplFrmt(value, 1);
};

//============================================================================================
// 차트
//============================================================================================
/**
 * 발전원별 차트를 생성
 */
scwin.searchChartSetcsc = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerSetcsc";
	rMateChartH5.create($p.id + "chartPrdctnSttusSetcsc", grpPrdctnSttusSetcscChart.getID(), chartVars, "100%", "100%");
};

/**
 * 발전원별 차트 설정
 */
scwin.chartReadyHandlerSetcsc = function(id) {
	var chartData = [];
	var dataList = dltPrdctnSttusSetcscByChartList.getAllJSON();

	for (var idx = 0; idx < dataList.length; idx++) {
		var obj = {
			"Name" : dataList[idx].elcpwstnNm,
			"Plan" : dataList[idx].elyrsQyPlan,
			"Acmslt" : dataList[idx].elyrsQyAcmslt,
			"Acmtrt" : dataList[idx].elyrsQyAcmtrt
		}
		chartData.push(obj);
	}

	var maxPlanData = chartData.reduce((max, obj) => Math.max(max, obj.Plan), 0);
	var maxAcmsltData = chartData.reduce((max, obj) => Math.max(max, obj.Acmslt), 0);
	var maxAcmtrtData = chartData.reduce((max, obj) => Math.max(max, obj.Acmtrt), 0);
	var maxData = maxPlanData > maxAcmsltData ? maxPlanData : maxAcmsltData;

	var prdctnChartUnit = Math.max(scwin.initData.chart.prdctnChartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var cnstnChartUnit = Math.max(scwin.initData.chart.cnstnChartUnit, Math.pow(10, String(maxAcmtrtData.toFixed(0)).length - 2));
	var intervalElyrsQy = Math.ceil((maxData / scwin.initData.chart.prdctnChartIntervalCount) / prdctnChartUnit) * prdctnChartUnit;
	var intervalAcmtrt = Math.ceil((maxAcmtrtData / scwin.initData.chart.cnstnChartIntervalCount) / cnstnChartUnit) * cnstnChartUnit;

	var radValue = radSeletChart.getText();
	var index = grdPrdctnSttusSetcscList.getFocusedRowIndex();
	var setcscNm = grdPrdctnSttusSetcscList.getCellData(index, "setcscNm");
	var title = radValue + "&amp;nbsp;" + setcscNm;
	var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" borderStyle="none">'
		+ '	<Options>'
		+ '		<Caption text="' + title + ' 생산전력 현황" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '		<Legend defaultMouseOverAction="true"/>'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+ '	<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="Name" padding="0.7"/>'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxisL" interval="' + intervalElyrsQy + '" formatter="{numFmt}" title="MWh"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '				<series>'
		+ '					<Column2DSeries yField="Plan" displayName="계획량(MWh)">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor1 + '"/>'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate/>'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '					<Column2DSeries yField="Acmslt" displayName="실적량(MWh)">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor2 + '"/>'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate/>'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '				</series>'
		+ '			</Column2DSet>'
		+ '			<Line2DSeries yField="Acmtrt" radius="4.5" labelPosition="up" itemRenderer="CircleItemRenderer" displayName="달성률(%)">'
		+ '				<stroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</stroke>'
		+ '				<lineStroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</lineStroke>'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxisR" interval="' + intervalAcmtrt + '" formatter="{numFmt}" title="%"/>'
		+ '				</verticalAxis>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate/>'
		+ '				</showDataEffect>'
		+ '			</Line2DSeries>'
		+ '		</series>'
		+'		<verticalAxisRenderers>'
		+'			<Axis2DRenderer axis="{vAxisL}" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
		+'			<Axis2DRenderer axis="{vAxisR}" placement="right" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
		+'		</verticalAxisRenderers>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		//+ '			<ScrollableAxisRenderer axis="{hAxis}" visibleItemSize="10"/>'
		+ '		</horizontalAxisRenderers>'
		+ '</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 부서별 차트를 생성
 */
scwin.searchChartDept = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerDept";
	rMateChartH5.create($p.id + "chartPrdctnSttusDept", grpPrdctnSttusDeptChart.getID(), chartVars, "100%", "100%");
};

/**
* 부서별 차트 설정
*/
scwin.chartReadyHandlerDept = function(id) {
	var chartData = [];
	var dataList = dltPrdctnSttusDeptByChartList.getAllJSON();

	for (var idx = 0; idx < dataList.length; idx++) {
		var obj = {
			"Name" : dataList[idx].elcpwstnNm,
			"Plan" : dataList[idx].elyrsQyPlan,
			"Acmslt" : dataList[idx].elyrsQyAcmslt,
			"Acmtrt" : dataList[idx].elyrsQyAcmtrt
		}
		chartData.push(obj);
	}

	var maxPlanData = chartData.reduce((max, obj) => Math.max(max, obj.Plan), 0);
	var maxAcmsltData = chartData.reduce((max, obj) => Math.max(max, obj.Acmslt), 0);
	var maxAcmtrtData = chartData.reduce((max, obj) => Math.max(max, obj.Acmtrt), 0);
	var maxData = maxPlanData > maxAcmsltData ? maxPlanData : maxAcmsltData;

	var prdctnChartUnit = Math.max(scwin.initData.chart.prdctnChartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var cnstnChartUnit = Math.max(scwin.initData.chart.cnstnChartUnit, Math.pow(10, String(maxAcmtrtData.toFixed(0)).length - 2));
	var intervalElyrsQy = Math.ceil((maxData / scwin.initData.chart.prdctnChartIntervalCount) / prdctnChartUnit) * prdctnChartUnit;
	var intervalAcmtrt = Math.ceil((maxAcmtrtData / scwin.initData.chart.cnstnChartIntervalCount) / cnstnChartUnit) * cnstnChartUnit;

	var radValue = radSeletChart.getText();
	var index = grdPrdctnSttusDeptByList.getFocusedRowIndex();
	var deptNm = grdPrdctnSttusDeptByList.getCellData(index, "deptNm");
	var title = radValue + "&amp;nbsp;" + deptNm;
	var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
	'<rMateChart backgroundColor="#FFFFFF"  borderStyle="none">'
	+'	<Options>'
	+'		<Caption text="' + title + ' 생산전력 현황" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
	+'		<Legend defaultMouseOverAction="true"/>'
	+'	</Options>'
	+'	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
	+'	<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
	+'		<horizontalAxis>'
	+'			<CategoryAxis id="hAxis" categoryField="Name" padding="0.7"/>'
	+'		</horizontalAxis>'
	+'		<verticalAxis>'
	+'			<LinearAxis id="vAxisL" interval="' + intervalElyrsQy + '" formatter="{numFmt}" title="MWh"/>'
	+'		</verticalAxis>'
	+'		<series>'
	+'			<Column2DSet type="clustered" maxColumnWidth="25">'
	+'				<series>'
	+'					<Column2DSeries yField="Plan" displayName="계획량(MWh)">'
	+'						<fill>'
	+'							<SolidColor color="' + solidColor1 + '"/>'
	+'						</fill>'
	+'						<showDataEffect>'
	+'							<SeriesInterpolate/>'
	+'						</showDataEffect>'
	+'					</Column2DSeries>'
	+'					<Column2DSeries yField="Acmslt" displayName="실적량(MWh)">'
	+'						<fill>'
	+'							<SolidColor color="' + solidColor2 + '"/>'
	+'						</fill>'
	+'						<showDataEffect>'
	+'							<SeriesInterpolate/>'
	+'						</showDataEffect>'
	+'					</Column2DSeries>'
	+'				</series>'
	+'			</Column2DSet>'
	+'			<Line2DSeries yField="Acmtrt" radius="4.5" labelPosition="up" itemRenderer="CircleItemRenderer" displayName="달성률(%)">'
	+'				<stroke>'
	+'					<Stroke color="#F9BD03" weight="3"/>'
	+'				</stroke>'
	+'				<lineStroke>'
	+'					<Stroke color="#F9BD03" weight="3"/>'
	+'				</lineStroke>'
	+'				<verticalAxis>'
	+'					<LinearAxis id="vAxisR" interval="' + intervalAcmtrt + '" formatter="{numFmt}" title="%"/>'
	+'				</verticalAxis>'
	+'				<showDataEffect>'
	+'					<SeriesInterpolate/>'
	+'				</showDataEffect>'
	+'			</Line2DSeries>'
	+'		</series>'
	+'		<verticalAxisRenderers>'
	+'			<Axis2DRenderer axis="{vAxisL}" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
	+'			<Axis2DRenderer axis="{vAxisR}" placement="right" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
	+'		</verticalAxisRenderers>'
	+'		<horizontalAxisRenderers>'
	+'			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
	+'		</horizontalAxisRenderers>'
	+'	</Combination2DChart>'
	+'</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

// 월간 전력거래량(누계) 달성률 계산_240122
scwin.fMlyElyrsQyAcmtrtCalc = function() {
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		var mlyElyrsQyPlanData = grdPrdctnSttusSetcscList.getFooterData("fMlyElyrsQyPlan");
		var mlyElyrsQyAcmsltData = grdPrdctnSttusSetcscList.getFooterData("fMlyElyrsQyAcmslt");
		return mlyElyrsQyAcmsltData / mlyElyrsQyPlanData * 100;
	} else if (tabIdx == 1) {
		var mlyElyrsQyPlanData = grdPrdctnSttusDeptByList.getFooterData("fMlyElyrsQyPlan");
		var mlyElyrsQyAcmsltData = grdPrdctnSttusDeptByList.getFooterData("fMlyElyrsQyAcmslt");
		return mlyElyrsQyAcmsltData / mlyElyrsQyPlanData * 100;
	}
};

// 연간 전력거래량(누계) 달성률 계산_240122
scwin.fFyerElyrsQyAcmtrtCalc = function() {
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		var fyerElyrsQyPlanData = grdPrdctnSttusSetcscList.getFooterData("fFyerElyrsQyPlan");
		var fyerElyrsQyAcmsltData = grdPrdctnSttusSetcscList.getFooterData("fFyerElyrsQyAcmslt");
	} else if (tabIdx == 1) {
		var fyerElyrsQyPlanData = grdPrdctnSttusDeptByList.getFooterData("fFyerElyrsQyPlan");
		var fyerElyrsQyAcmsltData = grdPrdctnSttusDeptByList.getFooterData("fFyerElyrsQyAcmslt");
	}
	return fyerElyrsQyAcmsltData / fyerElyrsQyPlanData * 100;
};

scwin.fMlyEqpUtlzRtCalc = function() {
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		var prdctnSttusList = grdPrdctnSttusSetcscList.getAllJSON();
	} else if (tabIdx == 1) {
		var prdctnSttusList = grdPrdctnSttusDeptByList.getAllJSON();
	}

	var idx = 0;
	var avg = 0;
	prdctnSttusList.forEach(obj => {
		if (obj.mlyEqpUtlzRt) {
			idx++;
			avg += obj.mlyEqpUtlzRt;
		}
	});
	return avg / idx;
};

scwin.fFyerEqpUtlzRtCalc = function(type) {
