/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm1 = document.getElementById($p.id + "tabControl_tab_tabMenu1_tabHTML").title;
	var subTitleNm2 = document.getElementById($p.id + "tabControl_tab_tabMenu2_tabHTML").title;
	var tabIdx = tabControl.getSelectedTabIndex();

	if (tabIdx == 0) {
		// 엑셀 내부 타이틀 추가_240105
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 9,
			text 		: `${menuNm}_` + `${subTitleNm1}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdPrdctnSttusSetcscList, {
			fileName : `${menuNm}_` + `${subTitleNm1}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			useDataFormat: true,
			applyDataFormat : true,
			decimal : "auto"
		}, infoArr);
	} else if (tabIdx == 1) {
		// 엑셀 내부 타이틀 추가_240105
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 9,
			text 		: `${menuNm}_` + `${subTitleNm2}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdPrdctnSttusDeptByList, {
			fileName : `${menuNm}_` + `${subTitleNm2}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			useDataFormat: true,
			applyDataFormat : true,
			decimal : "auto"
		}, infoArr);
	}
};
